"use client";

import React, { useEffect, useMemo, useState } from "react";

type Mode = "public" | "developer" | "auditor";

type AnyJson = Record<string, any>;

function toStr(v: unknown): string {
  return typeof v === "string" ? v : "";
}

function toNum(v: unknown): number | null {
  const n = typeof v === "number" ? v : Number(v);
  return Number.isFinite(n) ? n : null;
}

function shortHash(h: string, left = 10, right = 8): string {
  if (!h) return "";
  if (h.length <= left + right + 3) return h;
  return `${h.slice(0, left)}…${h.slice(-right)}`;
}

function JsonBlock({ value }: { value: any }) {
  const pretty = useMemo(() => {
    try {
      return JSON.stringify(value ?? null, null, 2);
    } catch {
      return String(value);
    }
  }, [value]);

  return (
    <pre className="mt-2 max-h-[420px] overflow-auto rounded-xl border border-neutral-200 bg-neutral-50 p-3 text-xs leading-relaxed text-neutral-900">
      {pretty}
    </pre>
  );
}

async function fetchJson(url: string): Promise<{ ok: boolean; status: number; data: AnyJson | null }> {
  try {
    const res = await fetch(url, { cache: "no-store" });
    const status = res.status;
    if (!res.ok) return { ok: false, status, data: null };
    const data = (await res.json()) as AnyJson;
    return { ok: true, status, data };
  } catch {
    return { ok: false, status: 0, data: null };
  }
}

function Badge({ tone, children }: { tone: "ok" | "warn" | "bad" | "neutral"; children: React.ReactNode }) {
  const cls =
    tone === "ok"
      ? "bg-emerald-50 text-emerald-800 border-emerald-200"
      : tone === "warn"
        ? "bg-amber-50 text-amber-800 border-amber-200"
        : tone === "bad"
          ? "bg-rose-50 text-rose-800 border-rose-200"
          : "bg-neutral-50 text-neutral-800 border-neutral-200";
  return <span className={`inline-flex items-center rounded-full border px-2 py-0.5 text-xs ${cls}`}>{children}</span>;
}

function Section({ title, subtitle, children }: { title: string; subtitle?: string; children: React.ReactNode }) {
  return (
    <section className="rounded-2xl border border-neutral-200 bg-white p-5 shadow-sm">
      <div className="flex flex-col gap-1">
        <div className="text-base font-semibold text-neutral-900">{title}</div>
        {subtitle ? <div className="text-sm text-neutral-600">{subtitle}</div> : null}
      </div>
      <div className="mt-4">{children}</div>
    </section>
  );
}

/**
 * Phase 14 — Public Verification Console (PVC)
 */
export default function VerifyPage() {
  const [mode, setMode] = useState<Mode>("public");
  const [query, setQuery] = useState<string>("");
  const [isVerifying, setIsVerifying] = useState<boolean>(false);

  const [trust, setTrust] = useState<AnyJson | null>(null);
  const [origin, setOrigin] = useState<AnyJson | null>(null);
  const [checkpoint, setCheckpoint] = useState<AnyJson | null>(null);
  const [sth, setSth] = useState<AnyJson | null>(null);

  const [error, setError] = useState<string>("");

  const [showRawTrust, setShowRawTrust] = useState<boolean>(false);
  const [showRawOrigin, setShowRawOrigin] = useState<boolean>(false);
  const [showRawCheckpoint, setShowRawCheckpoint] = useState<boolean>(false);
  const [showRawSth, setShowRawSth] = useState<boolean>(false);

  useEffect(() => {
    (async () => {
      const t = await fetchJson("/.well-known/whenisdue-trust.json");
      if (t.ok) setTrust(t.data);
      const o = await fetchJson("/.well-known/whenisdue-origin.json");
      if (o.ok) setOrigin(o.data);
      const c = await fetchJson("/.well-known/registry-checkpoint.json");
      if (c.ok) setCheckpoint(c.data);
      const s = await fetchJson("/transparency/sth/latest.json");
      if (s.ok) setSth(s.data);
    })();
  }, []);

  const derived = useMemo(() => {
    const trustRoot = toStr(trust?.sth?.root_hash) || toStr(trust?.sth?.rootHash) || "";
    const trustSize = toNum(trust?.sth?.tree_size) ?? toNum(trust?.sth?.treeSize);

    const sthRoot = toStr(sth?.root_hash) || toStr(sth?.rootHash) || "";
    const sthSize = toNum(sth?.tree_size) ?? toNum(sth?.treeSize);

    const checkpointRoot = toStr(checkpoint?.rootHash) || toStr(checkpoint?.hash) || "";
    const checkpointSize = toNum(checkpoint?.treeSize);

    const issuer = toStr(trust?.issuer) || toStr(origin?.iss) || "https://whenisdue.com";
    const did = toStr(trust?.id) || "did:web:whenisdue.com";

    const rootCandidates = [trustRoot, sthRoot, checkpointRoot].filter(Boolean);
    const canonicalRoot = rootCandidates.length > 0 ? rootCandidates[0] : "";

    const rootAgreement =
      canonicalRoot &&
      rootCandidates.every((x) => x === canonicalRoot);

    return {
      issuer,
      did,
      trustRoot,
      trustSize,
      sthRoot,
      sthSize,
      checkpointRoot,
      checkpointSize,
      canonicalRoot,
      rootAgreement,
      trustTimestamp: toStr(trust?.sth?.timestamp) || toStr(trust?.sth?.created) || "",
      sthTimestamp: toStr(sth?.timestamp) || toStr(sth?.created) || "",
      checkpointTimestamp: toStr(checkpoint?.generatedAt) || toStr(checkpoint?.createdAt) || ""
    };
  }, [trust, origin, checkpoint, sth]);

  async function onVerify() {
    setIsVerifying(true);
    setError("");

    const [t, o, c, s] = await Promise.all([
      fetchJson("/.well-known/whenisdue-trust.json"),
      fetchJson("/.well-known/whenisdue-origin.json"),
      fetchJson("/.well-known/registry-checkpoint.json"),
      fetchJson("/transparency/sth/latest.json")
    ]);

    if (t.ok) setTrust(t.data);
    if (o.ok) setOrigin(o.data);
    if (c.ok) setCheckpoint(c.data);
    if (s.ok) setSth(s.data);

    const anyFail = !t.ok || !o.ok || !c.ok || !s.ok;
    if (anyFail) {
      const parts = [
        !t.ok ? "trust manifest" : null,
        !o.ok ? "origin card" : null,
        !c.ok ? "registry checkpoint" : null,
        !s.ok ? "transparency STH" : null
      ].filter(Boolean);
      setError(`Network/availability issue: could not fetch ${parts.join(", ")}.`);
    }

    setIsVerifying(false);
  }

  const statusTone: "ok" | "warn" | "bad" | "neutral" = useMemo(() => {
    if (error) return "warn";
    if (!derived.canonicalRoot) return "neutral";
    return derived.rootAgreement ? "ok" : "bad";
  }, [derived.canonicalRoot, derived.rootAgreement, error]);

  const statusText = useMemo(() => {
    if (error) return "Audit Pending (Network)";
    if (!derived.canonicalRoot) return "Unavailable";
    return derived.rootAgreement ? "Verified (Published Artifacts Agree)" : "Mismatch (Review Required)";
  }, [derived.canonicalRoot, derived.rootAgreement, error]);

  const helpText = useMemo(() => {
    if (error) {
      return "The console couldn’t fetch one or more verification artifacts. This is typically a connectivity or caching issue. Try again in a moment.";
    }
    if (!derived.canonicalRoot) {
      return "The verification artifacts are not currently available. This can occur during a deployment window.";
    }
    if (derived.rootAgreement) {
      return "The public trust manifest, transparency STH, and registry checkpoint agree on the same root hash. For cryptographic verification, use the CLI verifier (signature + inclusion proof).";
    }
    return "The published artifacts disagree on the root hash. This warrants investigation (cache, partial publish, or integrity anomaly). Use the CLI verifier and compare artifacts from a clean network.";
  }, [derived.canonicalRoot, derived.rootAgreement, error]);

  const layoutGrid = mode === "auditor" ? "lg:grid-cols-3" : "lg:grid-cols-2";

  return (
    <main className="mx-auto w-full max-w-6xl px-4 py-8">
      {/* Header */}
      <div className="flex flex-col gap-4 rounded-2xl border border-neutral-200 bg-white p-6 shadow-sm">
        <div className="flex flex-col gap-2">
          <div className="text-2xl font-semibold tracking-tight text-neutral-900">Public Verification Console</div>
          <div className="text-sm text-neutral-600">
            Independently verifiable registry integrity—designed for citizens, developers, and auditors.
          </div>
        </div>

        {/* Mode Switch */}
        <div className="flex flex-wrap items-center gap-2">
          <button
            className={`rounded-xl border px-3 py-2 text-sm ${
              mode === "public" ? "border-neutral-900 bg-neutral-900 text-white" : "border-neutral-200 bg-white text-neutral-900"
            }`}
            onClick={() => setMode("public")}
          >
            Public Mode
          </button>
          <button
            className={`rounded-xl border px-3 py-2 text-sm ${
              mode === "developer" ? "border-neutral-900 bg-neutral-900 text-white" : "border-neutral-200 bg-white text-neutral-900"
            }`}
            onClick={() => setMode("developer")}
          >
            Developer Mode
          </button>
          <button
            className={`rounded-xl border px-3 py-2 text-sm ${
              mode === "auditor" ? "border-neutral-900 bg-neutral-900 text-white" : "border-neutral-200 bg-white text-neutral-900"
            }`}
            onClick={() => setMode("auditor")}
          >
            Auditor Mode
          </button>

          <div className="ml-auto flex items-center gap-2">
            <Badge tone={statusTone}>{statusText}</Badge>
            <button
              className="rounded-xl border border-neutral-900 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
              onClick={onVerify}
              disabled={isVerifying}
            >
              {isVerifying ? "Verifying…" : "Verify Now"}
            </button>
          </div>
        </div>

        {/* Search */}
        <div className="grid gap-2 md:grid-cols-[1fr_auto]">
          <input
            className="w-full rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 outline-none focus:border-neutral-400"
            placeholder="Optional: paste a Due Item ID / tracker slug / receipt reference (for future deep verification)."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
          <button
            className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-400"
            onClick={() => {}}
            disabled
            title="Entry-level verification can be added after the PVC foundation is locked."
          >
            Verify Entry (Soon)
          </button>
        </div>

        <div className="text-sm text-neutral-700">{helpText}</div>
      </div>

      {/* Core Panels */}
      <div className={`mt-6 grid grid-cols-1 gap-4 ${layoutGrid}`}>
        <Section title="Current Version of Record" subtitle="The root hash acts as the digital fingerprint of the published registry state.">
          <div className="grid grid-cols-1 gap-3">
            <div className="flex flex-wrap items-center gap-2">
              <div className="text-sm font-medium text-neutral-900">Root Hash</div>
              <span className="text-sm text-neutral-700">{derived.canonicalRoot ? shortHash(derived.canonicalRoot, 18, 14) : "—"}</span>
              {derived.canonicalRoot ? (
                <span className="text-xs text-neutral-500">(full in Developer Mode)</span>
              ) : null}
            </div>

            <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
              <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
                <div className="text-xs text-neutral-600">Trust Manifest</div>
                <div className="mt-1 text-sm text-neutral-900">
                  size: {derived.trustSize ?? "—"} · time: {derived.trustTimestamp || "—"}
                </div>
              </div>
              <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
                <div className="text-xs text-neutral-600">Transparency STH</div>
                <div className="mt-1 text-sm text-neutral-900">
                  size: {derived.sthSize ?? "—"} · time: {derived.sthTimestamp || "—"}
                </div>
              </div>
            </div>

            <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
              <div className="text-xs text-neutral-600">Registry Checkpoint</div>
              <div className="mt-1 text-sm text-neutral-900">
                size: {derived.checkpointSize ?? "—"} · time: {derived.checkpointTimestamp || "—"}
              </div>
            </div>
          </div>
        </Section>

        <Section title="Identity & Discovery" subtitle="Machine-readable identity anchors used by agents and auditors.">
          <div className="grid grid-cols-1 gap-3">
            <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
              <div className="text-xs text-neutral-600">Issuer</div>
              <div className="mt-1 text-sm text-neutral-900">{derived.issuer}</div>
            </div>

            <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
              <div className="text-xs text-neutral-600">DID</div>
              <div className="mt-1 text-sm text-neutral-900">{derived.did}</div>
            </div>

            <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
              <a
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                href="/.well-known/whenisdue-trust.json"
              >
                Open Trust Manifest
              </a>
              <a
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                href="/llms.txt"
              >
                Open llms.txt
              </a>
            </div>

            <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
              <a
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                href="/.well-known/whenisdue-origin.json"
              >
                Open Origin Card
              </a>
              <a
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                href="/transparency/sth/latest.json"
              >
                Open Latest STH
              </a>
            </div>
          </div>
        </Section>

        {mode === "auditor" ? (
          <Section
            title="Audit Navigation"
            subtitle="Pointers for consistency checks, diff review, and operational monitoring."
          >
            <div className="grid grid-cols-1 gap-3">
              <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
                <div className="text-xs text-neutral-600">Operational Notes</div>
                <div className="mt-1 text-sm text-neutral-900">
                  This console validates agreement between published artifacts. Full cryptographic validation (signature, inclusion
                  proof, consistency proof) is performed by the CLI verifier and transparency tools.
                </div>
              </div>

              <div className="grid grid-cols-1 gap-2 sm:grid-cols-2">
                <a
                  className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                  href="/.well-known/registry-checkpoint.json"
                >
                  Registry Checkpoint
                </a>
                <a
                  className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                  href="/transparency"
                >
                  Transparency Portal
                </a>
              </div>

              <div className="rounded-xl border border-neutral-200 bg-neutral-50 p-3">
                <div className="text-xs text-neutral-600">Mismatch Handling</div>
                <div className="mt-1 text-sm text-neutral-900">
                  If a mismatch appears, first rule out caching/partial publication by fetching from a clean network. If still present,
                  treat as an integrity anomaly: capture all artifacts + timestamps, then run the verifier against each.
                </div>
              </div>
            </div>
          </Section>
        ) : null}
      </div>

      {mode !== "public" ? (
        <div className="mt-6 grid grid-cols-1 gap-4 lg:grid-cols-2">
          <Section title="Trust Manifest Payload" subtitle="Raw JSON from /.well-known/whenisdue-trust.json">
            <div className="flex items-center gap-2">
              <button
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                onClick={() => setShowRawTrust((v) => !v)}
              >
                {showRawTrust ? "Hide Raw" : "Show Raw"}
              </button>
              <span className="text-xs text-neutral-500">cache: no-store</span>
            </div>
            {showRawTrust ? <JsonBlock value={trust} /> : null}
          </Section>

          <Section title="Origin Card Payload" subtitle="Raw JSON from /.well-known/whenisdue-origin.json">
            <div className="flex items-center gap-2">
              <button
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                onClick={() => setShowRawOrigin((v) => !v)}
              >
                {showRawOrigin ? "Hide Raw" : "Show Raw"}
              </button>
              <span className="text-xs text-neutral-500">cache: no-store</span>
            </div>
            {showRawOrigin ? <JsonBlock value={origin} /> : null}
          </Section>

          <Section title="Registry Checkpoint Payload" subtitle="Raw JSON from /.well-known/registry-checkpoint.json">
            <div className="flex items-center gap-2">
              <button
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                onClick={() => setShowRawCheckpoint((v) => !v)}
              >
                {showRawCheckpoint ? "Hide Raw" : "Show Raw"}
              </button>
              <span className="text-xs text-neutral-500">cache: no-store</span>
            </div>
            {showRawCheckpoint ? <JsonBlock value={checkpoint} /> : null}
          </Section>

          <Section title="Transparency STH Payload" subtitle="Raw JSON from /transparency/sth/latest.json">
            <div className="flex items-center gap-2">
              <button
                className="rounded-xl border border-neutral-200 bg-white px-3 py-2 text-sm text-neutral-900 hover:bg-neutral-50"
                onClick={() => setShowRawSth((v) => !v)}
              >
                {showRawSth ? "Hide Raw" : "Show Raw"}
              </button>
              <span className="text-xs text-neutral-500">cache: no-store</span>
            </div>
            {showRawSth ? <JsonBlock value={sth} /> : null}
          </Section>
        </div>
      ) : null}

      <div className="mt-8 text-sm text-neutral-500">
        <div className="rounded-2xl border border-neutral-200 bg-white p-5 shadow-sm">
          <div className="text-neutral-700">Verification Guidance</div>
          <ul className="mt-2 list-disc space-y-1 pl-5">
            <li>
              This console checks whether public artifacts agree on the same root hash (fast sanity check).
            </li>
            <li>
              For cryptographic verification (signature + inclusion/consistency proofs), use your CLI verifier toolchain.
            </li>
            <li>
              Network failures are shown as “Audit Pending (Network)” and should be retried before escalation.
            </li>
          </ul>
        </div>
      </div>
    </main>
  );
}